return [
  {
    json: {
      owner: 'gozemallick',
      repo: 'clara-AI',
      workflow_id: 'run_clara_pipeline.yml',
      ref: 'main',
      token: 'REPLACE_WITH_GITHUB_PAT',
      artifact_name: 'clara-pipeline-outputs'
    }
  }
];

const cfg = $json;

if (String(cfg.token || '').startsWith('REPLACE_')) {
  throw new Error('Replace REPLACE_WITH_GITHUB_PAT in Set GitHub Config before running.');
}

const dispatch = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.github.com/repos/${cfg.owner}/${cfg.repo}/actions/workflows/${cfg.workflow_id}/dispatches`,
  headers: {
    Authorization: `Bearer ${cfg.token}`,
    Accept: 'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28'
  },
  body: { ref: cfg.ref },
  json: true,
  resolveWithFullResponse: true,
  simple: false
});

return [
  {
    json: {
      ...cfg,
      dispatch_status_code: dispatch.statusCode,
      dispatched: dispatch.statusCode === 204,
      dispatched_at_utc: new Date().toISOString()
    }
  }
];

const cfg = $json;

const runsResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://api.github.com/repos/${cfg.owner}/${cfg.repo}/actions/workflows/${cfg.workflow_id}/runs?branch=${encodeURIComponent(cfg.ref)}&event=workflow_dispatch&per_page=10`,
  headers: {
    Authorization: `Bearer ${cfg.token}`,
    Accept: 'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28'
  },
  json: true
});

const dispatchedAtMs = Date.parse(cfg.dispatched_at_utc || '1970-01-01T00:00:00Z');
const run = (runsResp.workflow_runs || []).find((r) => Date.parse(r.created_at) >= dispatchedAtMs - 5000) || (runsResp.workflow_runs || [])[0] || null;

return [
  {
    json: {
      ...cfg,
      run_id: run ? run.id : null,
      run_status: run ? run.status : null,
      run_conclusion: run ? run.conclusion : null,
      run_url: run ? run.html_url : null
    }
  }
];

const cfg = $json;

if (!cfg.run_id) {
  return [
    {
      json: {
        ...cfg,
        artifact_id: null,
        artifact_archive_download_url: null
      }
    }
  ];
}

const artifactResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://api.github.com/repos/${cfg.owner}/${cfg.repo}/actions/runs/${cfg.run_id}/artifacts?per_page=100`,
  headers: {
    Authorization: `Bearer ${cfg.token}`,
    Accept: 'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28'
  },
  json: true
});

const artifact = (artifactResp.artifacts || []).find((a) => a.name === cfg.artifact_name) || null;

return [
  {
    json: {
      ...cfg,
      artifact_id: artifact ? artifact.id : null,
      artifact_archive_download_url: artifact ? artifact.archive_download_url : null
    }
  }
];

const j = $json;
const completed = j.run_status === 'completed';
const success = completed && j.run_conclusion === 'success';

return [
  {
    json: {
      summary: success
        ? 'Run completed successfully. Download clara-pipeline-outputs from the GitHub Actions run page.'
        : 'Run is not finished yet (or failed). Re-run this workflow after 30-60 seconds to refresh status.',
      run_status: j.run_status,
      run_conclusion: j.run_conclusion,
      run_url: j.run_url,
      artifact_name: j.artifact_name,
      artifact_archive_download_url: j.artifact_archive_download_url,
      input_how_to_send: 'Commit/push transcript files under data/demo and data/onboarding in the GitHub repo before dispatching this workflow.',
      output_where_to_get: 'Open run_url, then download artifact named clara-pipeline-outputs. It contains outputs/ and tracker/tasks.json.'
    }
  }
];
